  {"phrase":"luggage","translation":{"en":"Bags and suitcases you travel with","es":"Bolsas y maletas con las que viajas","pt":"Malas e bolsas com as quais você viaja","fr":"Sacs et valises avec lesquels vous voyagez","it":"Borse e valigie con cui viaggi"},"why":{"en":"Essential travel vocabulary","es":"Vocabulario esencial de viaje","pt":"Vocabulário essencial de viagem","fr":"Vocabulaire de voyage essentiel","it":"Vocabolario essenziale di viaggio"}},
  {"phrase":"trunk","translation":{"en":"The back storage area of a car","es":"El maletero del coche","pt":"O porta-malas do carro","fr":"Le coffre de la voiture","it":"Il bagagliaio della macchina"},"why":{"en":"Used when putting bags in a taxi or car","es":"Se usa al poner bolsas en un taxi o coche","pt":"Usado ao colocar malas em um táxi ou carro","fr":"Utilisé pour mettre des sacs dans un taxi ou une voiture","it":"Usato per mettere le borse in un taxi o in macchina"}},
  {"phrase":"highway","translation":{"en":"A fast, main road between cities","es":"Una carretera rápida y principal entre ciudades","pt":"Uma estrada rápida e principal entre cidades","fr":"Une route rapide et principale entre les villes","it":"Una strada veloce e principale tra le città"},"why":{"en":"Common word when discussing routes","es":"Palabra común al hablar de rutas","pt":"Palavra comum ao discutir rotas","fr":"Mot courant pour parler de trajets","it":"Parola comune quando si parla di percorsi"}},
  {"phrase":"traffic","translation":{"en":"Cars and vehicles on the road causing delays","es":"Coches y vehículos en la carretera causando retrasos","pt":"Carros e veículos na estrada causando atrasos","fr":"Voitures et véhicules sur la route causant des retards","it":"Auto e veicoli sulla strada che causano ritardi"},"why":{"en":"Important for understanding travel times","es":"Importante para entender los tiempos de viaje","pt":"Importante para entender os tempos de viagem","fr":"Important pour comprendre les temps de trajet","it":"Importante per capire i tempi di viaggio"}},
  {"phrase":"fasten","translation":{"en":"To close or secure something tightly","es":"Cerrar o asegurar algo firmemente","pt":"Fechar ou prender algo firmemente","fr":"Fermer ou attacher quelque chose solidement","it":"Chiudere o fissare qualcosa saldamente"},"why":{"en":"Used with seat belts and safety equipment","es":"Se usa con cinturones de seguridad y equipos de protección","pt":"Usado com cintos de segurança e equipamentos de proteção","fr":"Utilisé avec les ceintures de sécurité et les équipements de protection","it":"Usato con le cinture di sicurezza e le attrezzature di protezione"}}
