  {"phrase":"document","translation":{"en":"An official paper with important information","es":"Un papel oficial con información importante","pt":"Um papel oficial com informações importantes","fr":"Un papier officiel avec des informations importantes","it":"Un documento ufficiale con informazioni importanti"},"why":{"en":"Essential for talking about IDs, passports, etc.","es":"Esencial para hablar de identificaciones, pasaportes, etc.","pt":"Essencial para falar sobre identidades, passaportes, etc.","fr":"Essentiel pour parler de pièces d identité, passeports, etc.","it":"Essenziale per parlare di documenti di identità, passaporti, ecc."}},
  {"phrase":"passport","translation":{"en":"An official document for international travel","es":"Un documento oficial para viajes internacionales","pt":"Um documento oficial para viagens internacionais","fr":"Un document officiel pour les voyages internationaux","it":"Un documento ufficiale per i viaggi internazionali"},"why":{"en":"Key vocabulary for travel and identification","es":"Vocabulario clave para viajes e identificación","pt":"Vocabulário chave para viagens e identificação","fr":"Vocabulaire clé pour les voyages et l identification","it":"Vocabolario chiave per viaggi e identificazione"}},
  {"phrase":"ID number","translation":{"en":"A unique number on your identification card","es":"Un número único en tu tarjeta de identificación","pt":"Um número único no seu cartão de identidade","fr":"Un numéro unique sur votre carte d identité","it":"Un numero unico sulla tua carta d identità"},"why":{"en":"Needed when dealing with official processes","es":"Necesario al tratar con procesos oficiales","pt":"Necessário ao lidar com processos oficiais","fr":"Nécessaire pour les démarches officielles","it":"Necessario per le procedure ufficiali"}},
  {"phrase":"copy","translation":{"en":"A duplicate of an original document","es":"Un duplicado de un documento original","pt":"Uma cópia de um documento original","fr":"Un duplicata d un document original","it":"Una copia di un documento originale"},"why":{"en":"Often needed for official paperwork","es":"A menudo necesario para trámites oficiales","pt":"Frequentemente necessário para documentação oficial","fr":"Souvent nécessaire pour les documents officiels","it":"Spesso necessario per le pratiche ufficiali"}}
]'::jsonb WHERE language = 'english' AND level = 'beginner';

