  {"phrase":"supplies","translation":{"en":"Things you need for a task or daily life","es":"Cosas que necesitas para una tarea o la vida diaria","pt":"Coisas que você precisa para uma tarefa ou vida diária","fr":"Choses dont vous avez besoin pour une tâche ou la vie quotidienne","it":"Cose di cui hai bisogno per un compito o la vita quotidiana"},"why":{"en":"Useful word for talking about what you need to buy","es":"Palabra útil para hablar de lo que necesitas comprar","pt":"Palavra útil para falar sobre o que você precisa comprar","fr":"Mot utile pour parler de ce que vous devez acheter","it":"Parola utile per parlare di ciò che devi comprare"}},
  {"phrase":"wound","translation":{"en":"An injury where the skin is broken","es":"Una herida donde la piel está rota","pt":"Um ferimento onde a pele está rompida","fr":"Une blessure où la peau est ouverte","it":"Una ferita dove la pelle è rotta"},"why":{"en":"Important for describing injuries","es":"Importante para describir lesiones","pt":"Importante para descrever lesões","fr":"Important pour décrire des blessures","it":"Importante per descrivere ferite"}},
