  {"phrase":"masterpiece","translation":{"en":"An outstanding work of art or skill","es":"Una obra maestra de arte o habilidad","pt":"Uma obra-prima de arte ou habilidade","fr":"Un chef-d œuvre d art ou de savoir-faire","it":"Un capolavoro di arte o abilità"},"why":{"en":"Used to describe exceptional creative works","es":"Se usa para describir obras creativas excepcionales","pt":"Usado para descrever obras criativas excepcionais","fr":"Utilisé pour décrire des œuvres créatives exceptionnelles","it":"Usato per descrivere opere creative eccezionali"}},
  {"phrase":"mural","translation":{"en":"A large painting done directly on a wall","es":"Una gran pintura hecha directamente en una pared","pt":"Uma grande pintura feita diretamente em uma parede","fr":"Une grande peinture réalisée directement sur un mur","it":"Un grande dipinto fatto direttamente su un muro"},"why":{"en":"Key word for street art and public artwork","es":"Palabra clave para arte callejero y arte público","pt":"Palavra-chave para arte de rua e arte pública","fr":"Mot clé pour l art de rue et l art public","it":"Parola chiave per la street art e l arte pubblica"}},
  {"phrase":"defaced","translation":{"en":"Spoiled or damaged the appearance of something","es":"Estropeó o dañó la apariencia de algo","pt":"Estragou ou danificou a aparência de algo","fr":"A abîmé ou dégradé l apparence de quelque chose","it":"Ha rovinato o danneggiato l aspetto di qualcosa"},"why":{"en":"Often used when artwork or property is damaged","es":"Se usa a menudo cuando se daña una obra de arte o propiedad","pt":"Frequentemente usado quando uma obra de arte ou propriedade é danificada","fr":"Souvent utilisé quand une œuvre d art ou un bien est endommagé","it":"Spesso usato quando un opera d arte o una proprietà viene danneggiata"}},
  {"phrase":"barriers","translation":{"en":"Fences or obstacles to block access","es":"Vallas u obstáculos para bloquear el acceso","pt":"Cercas ou obstáculos para bloquear o acesso","fr":"Clôtures ou obstacles pour bloquer l accès","it":"Recinzioni o ostacoli per bloccare l accesso"},"why":{"en":"Used by authorities to protect or restrict areas","es":"Usadas por las autoridades para proteger o restringir áreas","pt":"Usadas pelas autoridades para proteger ou restringir áreas","fr":"Utilisées par les autorités pour protéger ou restreindre des zones","it":"Usate dalle autorità per proteggere o limitare aree"}}
